type GrammarParserBootstrap struct {
	input []byte
	vm    *virtualMachine
}

func NewGrammarParserBootstrap() *GrammarParserBootstrap {
	vm := NewVirtualMachine(bytecodeForGrammarParserBootstrap)
	return &GrammarParserBootstrap{vm: vm}
}
func (p *GrammarParserBootstrap) ParseGrammar() (Tree, error)               { return p.parseFn(5) }
func (p *GrammarParserBootstrap) ParseExpression() (Tree, error)            { return p.parseFn(1095) }
func (p *GrammarParserBootstrap) ParseSequence() (Tree, error)              { return p.parseFn(1287) }
func (p *GrammarParserBootstrap) ParsePrefix() (Tree, error)                { return p.parseFn(1355) }
func (p *GrammarParserBootstrap) ParseLabeled() (Tree, error)               { return p.parseFn(1482) }
func (p *GrammarParserBootstrap) ParseSuffix() (Tree, error)                { return p.parseFn(1583) }
func (p *GrammarParserBootstrap) ParsePrimary() (Tree, error)               { return p.parseFn(1819) }
func (p *GrammarParserBootstrap) ParseList() (Tree, error)                  { return p.parseFn(2806) }
func (p *GrammarParserBootstrap) ParseMissingClosingParen() (Tree, error)   { return p.parseFn(3061) }
func (p *GrammarParserBootstrap) ParseMissingClosingCurly() (Tree, error)   { return p.parseFn(3066) }
func (p *GrammarParserBootstrap) ParseMissingClosingBracket() (Tree, error) { return p.parseFn(3071) }
func (p *GrammarParserBootstrap) ParseMissingClosingSQuote() (Tree, error)  { return p.parseFn(3076) }
func (p *GrammarParserBootstrap) ParseMissingClosingDQuote() (Tree, error)  { return p.parseFn(3081) }
func (p *GrammarParserBootstrap) ParseMissingLabel() (Tree, error)          { return p.parseFn(3086) }
func (p *GrammarParserBootstrap) ParseMissingUnicodeOpen() (Tree, error)    { return p.parseFn(3106) }
func (p *GrammarParserBootstrap) ParseMissingUnicodeDigits() (Tree, error)  { return p.parseFn(3111) }
func (p *GrammarParserBootstrap) ParseMissingUnicodeClose() (Tree, error)   { return p.parseFn(3116) }
func (p *GrammarParserBootstrap) ParseMissingImportName() (Tree, error)     { return p.parseFn(3121) }
func (p *GrammarParserBootstrap) ParseMissingImportFrom() (Tree, error)     { return p.parseFn(3357) }
func (p *GrammarParserBootstrap) ParseMissingImportSrc() (Tree, error)      { return p.parseFn(3575) }
func (p *GrammarParserBootstrap) Parse() (Tree, error)                      { return p.parseFn(5) }
func (p *GrammarParserBootstrap) SetInput(input []byte)                     { p.input = input }
func (p *GrammarParserBootstrap) GetInput() []byte                          { return p.input }
func (p *GrammarParserBootstrap) SetLabelMessages(el map[int]int)           { p.vm.SetLabelMessages(el) }
func (p *GrammarParserBootstrap) SetShowFails(v bool)                       { p.vm.SetShowFails(v) }

func (p *GrammarParserBootstrap) parseFn(addr int) (Tree, error) {
	val, _, err := p.vm.MatchRule(p.input, addr)
	return val, err
}
